namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizer
{
    // Common English stop-words excluded from scoring.
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "the","is","at","which","on","a","an","and","or","but","in","with",
        "to","for","of","it","its","this","that","are","was","were","be",
        "been","being","have","has","had","do","does","did","will","would",
        "shall","should","may","might","can","could","not","no","from","by",
        "as","so","if","then","than","too","very","just","about","into",
        "through","during","before","after","above","below","between","each",
        "few","more","most","other","some","such","only","own","same","also"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordTokenizer();

    /// <summary>
    /// Produces an extractive summary by scoring sentences on word frequency
    /// and returning the top-ranked ones in their original order.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(text))
            return string.Empty;

        var sentences = SentenceSplitter()
            .Split(text)
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        // Build word-frequency map across the whole document.
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word))
                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
            }
        }

        // Score each sentence by the sum of its word frequencies.
        var scored = sentences
            .Select((s, index) => (Sentence: s, Index: index, Score: ScoreSentence(s, wordFrequency)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    public int CountSentences(string text) =>
        string.IsNullOrWhiteSpace(text)
            ? 0
            : SentenceSplitter().Split(text).Count(s => !string.IsNullOrWhiteSpace(s));

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequency)
    {
        var words = ExtractWords(sentence).Where(w => !StopWords.Contains(w)).ToList();
        if (words.Count == 0) return 0;
        return words.Sum(w => wordFrequency.GetValueOrDefault(w)) / (double)words.Count;
    }

    private static IEnumerable<string> ExtractWords(string text) =>
        WordTokenizer().Matches(text).Select(m => m.Value);
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizer _summarizer;

    public SummarizeController(DocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText must not be empty.");

        if (request.MaxSentences < 1)
            return BadRequest("MaxSentences must be at least 1.");

        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = _summarizer.CountSentences(request.DocumentText),
            SummarySentenceCount = _summarizer.CountSentences(summary)
        });
    }
}

